import{_ as t,o,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Google: Hacking Ethics","description":"https://edu-cyberpg.com/Technology/ethics-google-hacking.html","frontmatter":{"description":"https://edu-cyberpg.com/Technology/ethics-google-hacking.html"},"headers":[],"relativePath":"pen-testing/google-hacking-ethics.md","filePath":"pen-testing/google-hacking-ethics.md"}'),i={name:"pen-testing/google-hacking-ethics.md"};function s(n,e,l,h,c,g){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="google-hacking-ethics" tabindex="-1">Google: Hacking Ethics <a class="header-anchor" href="#google-hacking-ethics" aria-label="Permalink to &quot;Google: Hacking Ethics&quot;">​</a></h1><h2 id="google-hacking-ethics-1" tabindex="-1">GOOGLE HACKING ETHICS <a href="#google-hacking-ethics-part-2" id="google-hacking-ethics-part-2"></a> <a class="header-anchor" href="#google-hacking-ethics-1" aria-label="Permalink to &quot;GOOGLE HACKING ETHICS &lt;a href=&quot;#google-hacking-ethics-part-2&quot; id=&quot;google-hacking-ethics-part-2&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><a href="../.gitbook/assets/googlehackers%20(1).pdf">googlehackers (1).pdf</a></p><h3 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&amp;#x20;&quot;">​</a></h3><p><strong>Google: Book</strong></p><h3 id="searching" tabindex="-1">Searching <a class="header-anchor" href="#searching" aria-label="Permalink to &quot;Searching&quot;">​</a></h3><p>&quot;passport&quot; filetype:xls site:&quot;*.edu.*&quot; | site:&quot;*.gov.*&quot; | site:&quot;*.com.*&quot; | site:&quot;*.org.*&quot; | site:&quot;*.net.*&quot; | site:&quot;*.mil.*&quot;</p><p>&quot;passwordt&quot; filetype:xls site:&quot;*.edu.*&quot; | site:&quot;*.gov.*&quot; | site:&quot;*.com.*&quot; | site:&quot;*.org.*&quot; | site:&quot;*.net.*&quot; | site:&quot;*.mil.*&quot;</p><p>Use a search engine to find a page that is describing a relevant database by adding terms likely to appear the page. To find content on income inequality, for example, you might use a query like <strong>“income inequality” (database OR “data set” OR archive OR databank)</strong>. Look for a libguide or other finding tool developed by a librarian or info pro. Since most of these resources include the word guide or libguide in the URL, you can find a useful libguide on, say, entomology, by searching <strong>entomology (inurl:libguides OR inurl:guides OR inurl:researchguides).</strong> In addition, search for mentions of that resource. For example, if you find that FAOSTAT, the statistics portal of the UN Food and Agriculture Organization, is a useful source, try searching for mentions of its URL with a query like <strong>“fao.org/faostat/”</strong> (including the quotation marks).</p><p><a href="https://global.factiva.com/" target="_blank" rel="noreferrer">Factiva</a> is particularly good for finding specially-constructed, complex search queries that their internal search experts have designed for difficult or complex concepts. &lt;<a href="https://www.batesinfo.com/bates-infotips/searching-like-real-pros/" target="_blank" rel="noreferrer">more</a>&gt;</p><p><a href="https://www.wsj.com/articles/googles-featured-answers-aim-to-distill-truthbut-often-get-it-wrong-1510847867" target="_blank" rel="noreferrer"><strong>Google Has Picked an Answer for You—Too Bad It&#39;s Often Wrong</strong></a><br> Going beyond search, the internet giant is promoting a single result over all others, and many are contentious, improbable or laughably incorrect</p><h3 id="certified-ethical-hacker-google-hacking-hackers-for-charity-org-johnny-long-ethical-hacker-character-education-black-hat-computer-network-defender" tabindex="-1">Certified Ethical Hacker, Google Hacking, hackers for charity.org, Johnny Long ethical hacker, character education, black hat, computer network defender <a class="header-anchor" href="#certified-ethical-hacker-google-hacking-hackers-for-charity-org-johnny-long-ethical-hacker-character-education-black-hat-computer-network-defender" aria-label="Permalink to &quot;Certified Ethical Hacker, Google Hacking, hackers for charity.org, Johnny Long ethical hacker, character education, black hat, computer network defender&quot;">​</a></h3><h4 id="google-hacking-mini-guide-by-johnny-long-may-7-2004" tabindex="-1">Google Hacking Mini-Guide By Johnny Long May 7, 2004 <a class="header-anchor" href="#google-hacking-mini-guide-by-johnny-long-may-7-2004" aria-label="Permalink to &quot;Google Hacking Mini-Guide By Johnny Long May 7, 2004&quot;">​</a></h4><p>Using search engines such as <strong>Google, &quot;search engine hackers&quot;</strong> can easily find exploitable targets and sensitive data. This article outlines some of the techniques used by hackers and discusses how to prevent your site from becoming a victim of this form of information leakage.</p><h3 id="basic-search-techniques" tabindex="-1">Basic Search Techniques <a class="header-anchor" href="#basic-search-techniques" aria-label="Permalink to &quot;Basic Search Techniques&quot;">​</a></h3><p><a href="https://edu-cyberpg.com/Internet/Google-search-operators.html" target="_blank" rel="noreferrer">The Google search engine OPERATORS</a></p><p>This article outlines the more harmful applications of the Google search engine, techniques that have collectively been termed &quot;Google hacking.&quot; The intent of this article is to educate web administrators and the security community in the hopes of eventually stopping this form of information leakage.</p><p><strong>This document is an excerpt of the full </strong><em><strong>Google Hacker&#39;s Guide published by Johnny Long,</strong></em> was located at <a href="http://johnny.ihackstuff.com" target="_blank" rel="noreferrer">http://johnny.ihackstuff.com</a> which has been replaced with <a href="http://www.hackersforcharity.org/" target="_blank" rel="noreferrer">http://www.hackersforcharity.org/</a></p><p>VARIOUS OPERATORS AVAILABLE:</p><ul><li>Use the plus sign (+) to force a search for an overly common word. Use the minus sign (-) to exclude a term from a search. <em>No space follows these signs.</em></li><li>To search for a phrase, supply the phrase surrounded by double quotes (&quot; &quot;).</li><li>A period (.) serves as a single-character wildcard.</li><li>An asterisk (*) represents any word—not the completion of a word, as is traditionally used.</li></ul><p><a href="https://edu-cyberpg.com/Internet/Google-search-operators.html" target="_blank" rel="noreferrer">Google advanced operators help refine searches.</a> Advanced operators use a syntax such as the following:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>operator:search_term</span></span></code></pre></div><p>Notice that there&#39;s no space between the operator, the colon, and the search term.</p><ul><li>The site: operator instructs Google to restrict a search to a specific web site or domain. The web site to search must be supplied after the colon.</li><li>The filetype: operator instructs Google to search only within the text of a particular type of file. The file type to search must be supplied after the colon. Don&#39;t include a period before the file extension.</li><li>The link: operator instructs Google to search within hyperlinks for a search term.</li><li>The cache: operator displays the version of a web page as it appeared when Google crawled the site. The URL of the site must be supplied after the colon.</li><li>The intitle: operator instructs Google to search for a term within the title of a document.</li><li>The inurl: operator instructs Google to search only within the URL (web address) of a document. The search term must follow the colon.</li></ul><p>Google Hacking Techniques</p><p>By using the basic search techniques combined with Google&#39;s advanced operators, anyone can perform information-gathering and vulnerability-searching using Google. This technique is commonly referred to as Google hacking.<br> Site Mapping</p><p>To find every web page Google has crawled for a specific site, use the site: operator. Consider the following query:</p><p>site:<a href="http://www.microsoft.com" target="_blank" rel="noreferrer">http://www.microsoft.com</a> microsoft</p><p>This query searches for the word microsoft, restricting the search to the <a href="http://www.microsoft.com" target="_blank" rel="noreferrer">http://www.microsoft.com</a> web site. How many pages on the Microsoft web server contain the word microsoft? According to Google, all of them! Google searches not only the content of a page, but the title and URL as well. The word microsoft appears in the URL of every page on <a href="http://www.microsoft.com" target="_blank" rel="noreferrer">http://www.microsoft.com</a>. With a single query, an attacker gains a rundown of every web page on a site cached by Google.</p><p>There are some exceptions to this rule. If a link on the Microsoft web page points back to the IP address of the Microsoft web server, Google will cache that page as belonging to the IP address, not the <a href="http://www.microsoft.com" target="_blank" rel="noreferrer">http://www.microsoft.com</a> web server. In this special case, an attacker would simply alter the query, replacing the word microsoft with the IP address(es) of the Microsoft web server.<br></p><h4 id="finding-directory-listings" tabindex="-1">Finding Directory Listings <a class="header-anchor" href="#finding-directory-listings" aria-label="Permalink to &quot;Finding Directory Listings&quot;">​</a></h4><p>Directory listings provide a list of files and directories in a browser window instead of the typical text-and graphics mix generally associated with web pages. These pages offer a great environment for deep information gathering (see Figure 1).</p><p><a href="http://ptgmedia.pearsoncmg.com/images/art_fogie_googleguide1/elementLinks/fig01.jpg" target="_blank" rel="noreferrer"><strong>Figure 1</strong></a> <strong>A typical directory listing.</strong></p><p>Locating directory listings with Google is fairly straightforward. Figure 1 shows that most directory listings begin with the phrase Index of, which also shows in the title. An obvious query to find this type of page might be intitle:index.of, which may find pages with the term index of in the title of the document. Unfortunately, this query will return a large number of false positives, such as pages with the following titles:</p><ul><li>Index of Native American Resources on the Internet</li><li>LibDex—Worldwide index of library catalogues</li><li>Iowa State Entomology Index of Internet Resources</li></ul><p>Judging from the titles of these documents, it&#39;s obvious that not only are these web pages intentional, they&#39;re also not the directory listings we&#39;re looking for. Several alternate queries provide more accurate results:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">intitle:index.of </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;parent directory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">intitle:index.of name size</span></span></code></pre></div><p>These queries indeed provide directory listings by not only focusing on index.of in the title, but on keywords often found <em>inside</em> directory listings, such as parent directory, name, and size. Obviously, this search can be combined with other searches to find files of directories located in directory listings.</p><h4 id="versioning-obtaining-the-web-server-software-version" tabindex="-1">Versioning: Obtaining the Web Server Software/Version <a class="header-anchor" href="#versioning-obtaining-the-web-server-software-version" aria-label="Permalink to &quot;Versioning: Obtaining the Web Server Software/Version&quot;">​</a></h4><p>The exact version of the web server software running on a server is one piece of information an attacker needs before launching a successful attack against that web server. If an attacker connects directly to that web server, the HTTP (web) headers from that server can provide this essential information. It&#39;s possible, however, to retrieve similar information from Google&#39;s cache without ever connecting to the target server under investigation. One method involves using the information provided in a directory listing.</p><p>Figure 2 shows the bottom line of a typical directory listing. Notice that the directory listing includes the name of the server software as well as the version. An adept web administrator can fake this information, but often it&#39;s legitimate, allowing an attacker to determine what attacks may work against the server.</p><p><strong>Directory listing server.at example.</strong></p><p>This example was gathered using the following query:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>intitle:index.of server.at</span></span></code></pre></div><p>This query focuses on the term index of in the title and server at appearing at the bottom of the directory listing. This type of query can also be pointed at a particular web server:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>intitle:index.of server.at site:aol.com</span></span></code></pre></div><p>The result of this query indicates that gprojects.web.aol.com and vidup-r1.blue.aol.com both run Apache web servers.</p><p>It&#39;s also possible to determine the version of a web server based on default pages installed on that server. When a web server is installed, it generally will ship with a set of default web pages, like the Apache 1.2.6 page shown in <a href="http://ptgmedia.pearsoncmg.com/images/art_fogie_googleguide1/elementLinks/fig03.jpg" target="_blank" rel="noreferrer">Figure 3</a>:</p><p><strong>Figure 3 Apache test page.</strong></p><p>These pages can make it easy for a site administrator to get a web server running. By providing a simple page to test, the administrator can simply connect to his own web server with a browser to validate that the web server was installed correctly. Some operating systems even come with web server software already installed. In this case, an Internet user may not even realize that a web server is running on his machine. This type of casual behavior on the part of an Internet user will lead an attacker to rightly assume that the web server is not well maintained, and by extension is insecure. By further extension, the attacker can assume that the entire operating system of the server may be vulnerable by virtue of poor maintenance.</p><p>The following table provides a brief rundown of some queries that can locate various default pages.</p><table tabindex="0"><thead><tr><th><strong>Apache Server Version</strong></th><th><strong>Query</strong></th></tr></thead><tbody><tr><td>Apache 1.3.0-1.3.9</td><td>Intitle:Test.Page.for.Apache It.worked! this.web.site!</td></tr><tr><td>Apache 1.3.11-1.3.26</td><td>Intitle:Test.Page.for.Apache seeing.this.instead</td></tr><tr><td>Apache 2.0</td><td>Intitle:Simple.page.for.Apache Apache.Hook.Functions</td></tr><tr><td>Apache SSL/TLS</td><td>Intitle:test.page &quot;Hey, it worked !&quot; &quot;SSL/TLS-aware&quot;</td></tr><tr><td>Many IIS servers</td><td>intitle:welcome.to intitle:internet IIS</td></tr><tr><td>Unknown IIS server</td><td>intitle:&quot;Under construction&quot; &quot;does not currently have&quot;</td></tr><tr><td>IIS 4.0</td><td>intitle:welcome.to.IIS.4.0</td></tr><tr><td>IIS 4.0</td><td>allintitle:Welcome to Windows NT 4.0 Option Pack</td></tr><tr><td>IIS 4.0</td><td>allintitle:Welcome to Internet Information Server</td></tr><tr><td>IIS 5.0</td><td>allintitle:Welcome to Windows 2000 Internet Services</td></tr><tr><td>IIS 6.0</td><td>allintitle:Welcome to Windows XP Server Internet Services</td></tr><tr><td>Many Netscape servers</td><td>allintitle:Netscape Enterprise Server Home Page</td></tr><tr><td>Unknown Netscape server</td><td>allintitle:Netscape FastTrack Server Home Page</td></tr></tbody></table><br><h4 id="using-google-as-a-cgi-scanner" tabindex="-1">Using Google as a CGI Scanner <a class="header-anchor" href="#using-google-as-a-cgi-scanner" aria-label="Permalink to &quot;Using Google as a CGI Scanner&quot;">​</a></h4><p>To accomplish its task, a CGI scanner must know what exactly to search for on a web server. Such scanners often utilize a data file filled with vulnerable files and directories like the one shown below:</p><p>/cgi-bin/cgiemail/uargg.txt /random_banner/index.cgi /random_banner/index.cgi /cgi-bin/mailview.cgi /cgi-bin/maillist.cgi /cgi-bin/userreg.cgi /iissamples/ISSamples/SQLQHit.asp /iissamples/ISSamples/SQLQHit.asp /SiteServer/admin/findvserver.asp /scripts/cphost.dll /cgi-bin/finger.cgi</p><p>Combining a list like this one with a carefully crafted Google search, Google can be used as a CGI scanner. Each line can be broken down and used in either an index.of or inurl search to find vulnerable targets. For example, a Google search for this:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">allinurl:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">random_banner</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.cgi</span></span></code></pre></div><p>returns the results shown in <a href="http://ptgmedia.pearsoncmg.com/images/art_fogie_googleguide1/elementLinks/fig04.jpg" target="_blank" rel="noreferrer">Figure 4</a>.</p><p><a href="http://ptgmedia.pearsoncmg.com/images/art_fogie_googleguide1/elementLinks/fig04.jpg" target="_blank" rel="noreferrer"><strong>Figure 4</strong></a> <strong>Sample search using a line from a CGI scanner.</strong></p><p>A hacker can take sites returned from this Google search, apply a bit of hacker &quot;magic,&quot; and eventually get the broken random_banner program to cough up any file on that web server, including the password file, as shown in <a href="http://ptgmedia.pearsoncmg.com/images/art_fogie_googleguide1/elementLinks/fig05.jpg" target="_blank" rel="noreferrer">Figure 5</a>.</p><p><strong>Figure 5 Password file captured from a vulnerable site found using a Google search.</strong></p><p>Note that actual exploitation of a found vulnerability crosses the ethical line, and is not considered mere web searching.</p><p>Of the many Google hacking techniques we&#39;ve looked at, this technique is one of the best candidates for automation, because the CGI scanner vulnerability files can be very large. The gooscan tool, written by j0hnny, performs this and many other functions. Gooscan and automation are discussed below.</p><h3 id="google-automated-scanning" tabindex="-1">Google Automated Scanning <a class="header-anchor" href="#google-automated-scanning" aria-label="Permalink to &quot;Google Automated Scanning&quot;">​</a></h3><p>Google <a href="http://www.google.com/terms_of_service.html" target="_blank" rel="noreferrer">frowns on automation</a>: &quot;You may not send automated queries of any sort to Google&#39;s system without express permission in advance from Google. Note that &#39;sending automated queries&#39; includes, among other things:</p><ul><li>using any software which sends queries to Google to determine how a web site or web page &#39;ranks&#39; on Google for various queries;</li><li>&#39;meta-searching&#39; Google; and</li><li>performing &#39;offline&#39; searches on Google.&quot;</li></ul><p>Any user running an automated Google querying tool (with the exception of tools created with Google&#39;s extremely limited API) must obtain express permission in advance to do so. It&#39;s unknown what the consequences of ignoring these terms of service are, but it seems best to stay on Google&#39;s good side.</p><h4 id="gooscan" tabindex="-1">Gooscan <a class="header-anchor" href="#gooscan" aria-label="Permalink to &quot;Gooscan&quot;">​</a></h4><p>Gooscan is a UNIX (Linux/BSD/Mac OS X) tool that automates queries against Google search appliances (which are not governed by the same automation restrictions as their web-based brethren). For the security professional, gooscan serves as a front end for an external server assessment and aids in the information-gathering phase of a vulnerability assessment. For the web server administrator, gooscan helps discover what the web community may already know about a site thanks to Google&#39;s search appliance.</p><p>For more information about this tool, including the ethical implications of its use, see <a href="http://johnny.ihackstuff.com" target="_blank" rel="noreferrer">http://johnny.ihackstuff.com</a></p><p><a href="http://www.oocities.org/zuhair_ali/Misc/googlehacks.html" target="_blank" rel="noreferrer">Google Hacking Mini-Guide</a> Date: May 7, 2004 By Johnny Long.</p><h4 id="googledorks" tabindex="-1">Googledorks <a class="header-anchor" href="#googledorks" aria-label="Permalink to &quot;Googledorks&quot;">​</a></h4><p><em><strong>The term &quot;googledork&quot; was coined by the author and originally meant &quot;An inept or foolish person as revealed by Google.&quot;</strong></em> After a great deal of media attention, the term came to describe those who &quot;troll the Internet for confidential goods.&quot; Either description is fine, really. What matters is that the term <em><strong>googledork</strong></em><strong> conveys the concept that sensitive stuff is on the web, and Google can help you find it.</strong> The official googledorks page <a href="http://johnny.ihackstuff.com/googledorks" target="_blank" rel="noreferrer">http://johnny.ihackstuff.com/googledorks</a> lists many different examples of unbelievable things that have been dug up through Google by the maintainer of the page, Johnny Long. Each listing shows the Google search required to find the information, along with a description of why the data found on each page is so interesting.</p><h4 id="goopot" tabindex="-1">GooPot <a class="header-anchor" href="#goopot" aria-label="Permalink to &quot;GooPot&quot;">​</a></h4><p>The concept of a <em>honeypot</em> is very straightforward. According to <a href="http://www.techtarget.com/" target="_blank" rel="noreferrer">http://www.techtarget.com</a>, &quot;A honey pot is a computer system on the Internet that is expressly set up to attract and &#39;trap&#39; people who attempt to penetrate other people&#39;s computer systems.&quot;</p><p>To learn how new attacks might be conducted, the maintainers of a honeypot system monitor, dissect, and catalog each attack, focusing on those attacks that seem unique.</p><p>An extension of the classic honeypot system, a web-based honeypot or &quot;page pot&quot; (click <a href="http://www.gray-world.net/etc/passwd/" target="_blank" rel="noreferrer">here</a> to see what a page pot may look like) is designed to attract those employing the techniques outlined in this article. The concept is fairly straightforward. Consider a simple googledork entry like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>inurl:admin inurl:userlist</span></span></code></pre></div><p>This entry could easily be replicated with a web-based honeypot by creating an index.html page that referenced another index.html file in an /admin/userlist directory. If a web search engine such as Google was instructed to crawl the top-level index.html page, it would eventually find the link pointing to /admin/userlist/index.html. This link would satisfy the Google query of inurl:admin inurl:userlist, eventually attracting a curious Google hacker.</p><p>The referrer variable can be inspected to figure out how a web surfer found a web page through Google. This bit of information is critical to the maintainer of a page pot system, because it outlines the exact method the Google searcher used to locate the page pot system. The information aids in protecting other web sites from similar queries.</p><p>GooPot, the Google honeypot system, uses enticements based on the many techniques outlined in the googledorks collection and this document. In addition, the GooPot more closely resembles the juicy targets that Google hackers typically go after. Johnny Long, the administrator of the googledorks list, utilizes the GooPot to discover new search types and to publicize them in the form of googledorks listings, creating a self-sustaining cycle for learning about and protecting from search engine attacks.</p><p>Although the GooPot system is currently not publicly available, expect it to be made available early in the second quarter of 2004.</p><h3 id="protecting-yourself-from-google-hackers" tabindex="-1">Protecting Yourself from Google Hackers <a class="header-anchor" href="#protecting-yourself-from-google-hackers" aria-label="Permalink to &quot;Protecting Yourself from Google Hackers&quot;">​</a></h3><p>The following list provides some basic methods for protecting yourself from Google hackers:</p><ul><li><p><strong>Keep your sensitive data off the web!</strong> Even if you think you&#39;re only putting your data on a web site temporarily, there&#39;s a good chance that you&#39;ll either forget about it, or that a web crawler might find it. Consider more secure ways of sharing sensitive data, such as SSH/SCP or encrypted email.</p></li><li><p><strong>Googledork!</strong> Use the techniques outlined in this article (and the full Google Hacker&#39;s Guide) to check your site for sensitive information or vulnerable files. Use gooscan from <a href="http://johnny.ihackstuff.com" target="_blank" rel="noreferrer">http://johnny.ihackstuff.com</a> to scan your site for bad stuff, but <em>first get advance express permission from Google</em>!Without advance express permission, Google could come after you for violating their terms of service. The author is currently not aware of the exact implications of such a violation. But why anger the &quot;Goo-Gods&quot;?!</p></li><li><p><strong>TIP</strong></p><p>Check the official googledorks web site on a regular basis to keep up on the latest tricks and techniques.</p></li><li><p><strong>Consider removing your site from Google&#39;s index.</strong> The Google <a href="http://www.google.com/webmasters/" target="_blank" rel="noreferrer">webmasters FAQ</a> provides invaluable information about ways to properly protect and/or expose your site to Google. From that page: <strong>&quot;Please have the webmaster for the page in question contact us with proof that he/she is indeed the webmaster</strong>. This proof must be in the form of a root level page on the site in question, requesting removal from Google. Once we receive the URL that corresponds with this root level page, we will remove the offending page from our index.&quot; In some cases, you may want to remove individual pages or snippets from Google&#39;s index. This is also a straightforward process that can be accomplished by following the steps outlined at <a href="http://www.google.com/remove.html" target="_blank" rel="noreferrer">http://www.google.com/remove.html</a></p></li><li><p><strong>Use a robots.txt file.</strong> Web crawlers are supposed to follow the <a href="http://www.robotstxt.org/" target="_blank" rel="noreferrer">robots exclusion standard</a>. This standard outlines the procedure for &quot;politely requesting&quot; that web crawlers ignore all or part of your web site. I must note that hackers may not have any such scruples, as this file is certainly a suggestion. The major search engine&#39;s crawlers honor this file and its contents. For examples and suggestions for using a robots.txt file, see <a href="http://www.robotstxt.org/" target="_blank" rel="noreferrer">http://www.robotstxt.org</a>.</p></li></ul><p><strong>Thanks</strong> to God, my family, Seth, and the googledork community for all the support. Happy Googling!<br><a href="http://www.hackersforcharity.org" target="_blank" rel="noreferrer">http://www.hackersforcharity.org</a><br> j0hnny <a href="http://johnny.ihackstuff.com" target="_blank" rel="noreferrer">http://johnny.ihackstuff.com</a> <a href="https://twitter.com/ihackstuff" target="_blank" rel="noreferrer">https://twitter.com/ihackstuff</a></p><p>--</p><p><a href="http://techarta.com/5649/exclusive-interview-with-ethical-hacker-himanshu-sharma/" target="_blank" rel="noreferrer">Interview With Himanshu Sharma</a> - One of India&#39;s Finest Ethical Hacker <a href="http://wanted-hacker.blogspot.com/" target="_blank" rel="noreferrer">нα¢кєя BLOG</a></p>`,89)])])}const u=t(i,[["render",s]]);export{d as __pageData,u as default};
